args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?actress ?actressLabel
WHERE {
  ?film wdt:P161 wd:Q83410 ;
        wdt:P577 ?date ;
        wdt:P161 ?actress ;
        wdt:P31 wd:Q11424 .
  ?actress wdt:P21 wd:Q6581099 .
  FILTER (STRSTARTS(STR(?date), "194"))
  ?actress rdfs:label ?actressLabel .
  FILTER (lang(?actressLabel) = 'en')
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT DISTINCT ?actress ?actressLabel
WHERE {
  ?film wdt:P161 wd:Q83410 ;
        wdt:P577 ?date ;
        wdt:P31 wd:Q11424 ;
        wdt:P161 ?actress .
  ?actress wdt:P21 wd:Q6581099 .
  BIND(xsd:integer(SUBSTR(STR(?date), 1, 4)) AS ?year)
  FILTER(?year >= 1940 && ?year <= 1949)
  ?actress rdfs:label ?actressLabel .
  FILTER(lang(?actressLabel) = 'en')
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?actress ?actressLabel
WHERE {
  ?film wdt:P31 wd:Q11424 ;
        wdt:P161 wd:Q83410 ;
        wdt:P161 ?actress ;
        wdt:P577 ?date .
  ?actress wdt:P21 wd:Q6581099 .
  FILTER(?actress != wd:Q83410)
  FILTER(REGEX(STR(?date), "^194[0-9]"))
  ?actress rdfs:label ?actressLabel .
  FILTER(LANG(?actressLabel) = 'en')
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?actress ?actressLabel
WHERE {
  ?film wdt:P31 wd:Q11424 ;
        wdt:P577 ?date ;
        wdt:P161 wd:Q83410 ;
        wdt:P161 ?actress .
  ?actress wdt:P21 wd:Q6581099 .
  FILTER(STRSTARTS(STR(?date), "194"))
  FILTER(?actress != wd:Q83410)
  ?actress rdfs:label ?actressLabel .
  FILTER(LANG(?actressLabel) = 'en')
